import{_ as a,o,c as n,ag as t}from"./chunks/framework.CAXxHpAX.js";const v=JSON.parse('{"title":"20世纪70年代的外交成就有？（按时间顺","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-25.md","filePath":"notes/note-25.md"}'),e={name:"notes/note-25.md"};function r(s,p,l,c,d,b){return o(),n("div",null,[...p[0]||(p[0]=[t('<h1 id="_20世纪70年代的外交成就有-按时间顺" tabindex="-1">20世纪70年代的外交成就有？（按时间顺 <a class="header-anchor" href="#_20世纪70年代的外交成就有-按时间顺" aria-label="Permalink to &quot;20世纪70年代的外交成就有？（按时间顺&quot;">​</a></h1><p>1、20世纪70年代的外交成就有？（按时间顺序写！）恢复联合国合法席位（71年，26届）；中美关系正常化（72年）；中日建交（72年）；中美建交（79年）</p><p>2、标志海峡两岸关系发生历史性变化的事件？台湾调整“三不”政策。</p><p>3、我国的外交政策是？外交原则是？ 独立自主和平外交政策 和平共处五项原则</p><p>4、恢复联合国合法席位的根本原因是？中国国际地位的提高</p><p>5、两弹一星是什么？ 导弹、核弹、人造地球卫星东方红一号</p><p>6、第一位航天员是？ 杨利伟</p><p>7、新中国成立后，科学文化方针是什么？ 百花齐放、百家争鸣</p><p>8、香港、澳门能够顺利回归祖国的根本原因是？综合国力的提高</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">9、香港、澳门能够顺利回归祖国的意义：</span>中国人民洗雪了百年国耻，在完成祖国统一大业的道路上迈出了重要一步。</p><p>1</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">0、中国恢复联合国合法席位的意义：</span>中国外交重大胜利，中国国际地位和国际影响力进一步提高和扩大；中国积极参与国际事务，作为联合国安理会常任理事国之一，发挥重要作用。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、经济特区：</span>1980年深圳、厦门、汕头、珠海</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、沿海开放城市：</span>1984年，广州等14个</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、沿海经济开放区：</span>1985年，长江三角洲、珠江三角洲、闽南三角洲</p><p>4、1988年，海南经济特区</p><p>5、1990年，上海浦东开发区</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、对外开放格局：</span>经济特区-沿海开放城市-沿海经济开放区-内地的全方位、多层次、宽领域。</p><p>7、2001年，中国加入世贸组织。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、意义：</span>为我国参与经济全球化开辟了新途径，为国民经济和社会发展开拓了新空间。</p><p>9、1992年，邓小平南方谈话，进一步解放人民的思想，推动改革开放和社会主义现代化建设进入新阶段。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">城市经济体制改革：</span>1984年，中心环节：增强企业活力。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">城市经济体制改革的意义：</span>企业有了经营自主权；大大调动了企业、职工的积极性，增强了企业的活力。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">经济特区：</span>1980年，深圳（窗口）、珠海、汕头、厦门。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">经济特区的作用：</span>引进外资、先进技术和管理经验，推动国内的进一步改革，扩大对外经济交流，发展社会主义现代化事业起到重要作用。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">抗美援朝的意义：</span></p><p>①抵御了帝国主义侵略扩张，捍卫了新中国安全，保卫了中国人民和平生活；</p><p>②大大提高了我国的国际地位；</p><p>③是中国人民站起来后屹立于世界东方的宣言书，是中华民族走向伟大复兴的重要里程碑；</p><p>④打破了美军不可战胜的神话；</p><p>⑤稳定了朝鲜半岛局势，维护了亚洲和世界和平。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">抗美援朝精神：</span>爱国主义、革命英雄主义</p>',32)])])}const _=a(e,[["render",r]]);export{v as __pageData,_ as default};
